// ═══════════════════════════════════════
// AGENTE MANTENIMIENTO — Detección de Degradación Gradual
// ═══════════════════════════════════════
const input = $('Webhook Mantenimiento').first().json.body || $('Webhook Mantenimiento').first().json;
const area = input.area || 'unknown';
const dailyData = $('Tendencia Semanal').all().map(i => i.json);
const existingOrder = $('Verificar Orden Existente').first().json;

const MIN_GROWTH_PCT = 1.5;
const MIN_DAYS = 5;
const MAX_SPIKE_PCT = 50;

// Si ya existe orden pendiente, skip
if (existingOrder && existingOrder.id) {
  return [{ json: {
    action: 'existing_order',
    area,
    order_id: existingOrder.id,
    priority: existingOrder.prioridad,
    save_order: false
  } }];
}

// Datos insuficientes
if (!dailyData || dailyData.length < 3) {
  return [{ json: {
    action: 'insufficient_data',
    area,
    days_available: dailyData ? dailyData.length : 0,
    save_order: false
  } }];
}

// ── Calcular crecimiento diario ──
const growths = [];
for (let i = 1; i < dailyData.length; i++) {
  const prev = Number(dailyData[i-1].avg_reading);
  const curr = Number(dailyData[i].avg_reading);
  const pctChange = prev > 0 ? ((curr - prev) / prev) * 100 : 0;
  growths.push(pctChange);
}

// Verificar spikes (salto >50% = no es degradación gradual)
const hasSpike = growths.some(g => Math.abs(g) > MAX_SPIKE_PCT);
if (hasSpike) {
  return [{ json: {
    action: 'spike_detected',
    area,
    reason: 'Detectado spike >50%, no es degradación gradual',
    growths: growths.map(g => Math.round(g * 100) / 100),
    save_order: false
  } }];
}

// Contar días con crecimiento positivo sostenido
const positiveDays = growths.filter(g => g >= MIN_GROWTH_PCT).length;
const avgGrowth = growths.reduce((s, g) => s + g, 0) / growths.length;

const isDegrading = positiveDays >= Math.min(MIN_DAYS, growths.length) && avgGrowth >= MIN_GROWTH_PCT;

if (!isDegrading) {
  return [{ json: {
    action: 'trend_normal',
    area,
    avg_daily_growth_pct: Math.round(avgGrowth * 100) / 100,
    days_analyzed: dailyData.length,
    save_order: false
  } }];
}

// ── Determinar prioridad ──
let priority = 'baja';
if (avgGrowth >= 5.0) priority = 'urgente';
else if (avgGrowth >= 3.0) priority = 'alta';
else if (avgGrowth >= 2.0) priority = 'media';

const emaStart = Number(dailyData[0].avg_ema) || 0;
const emaCurrent = Number(dailyData[dailyData.length - 1].avg_ema) || 0;

const prioEmoji = { urgente: '🔴', alta: '🟠', media: '🟡', baja: '🟢' };

const message = `🔧 <b>MANTENIMIENTO PREVENTIVO</b>\n` +
  `${prioEmoji[priority] || '🟡'} Prioridad: <b>${priority.toUpperCase()}</b>\n` +
  `📍 Área: <b>${area}</b>\n` +
  `📈 Tendencia: +${avgGrowth.toFixed(1)}% diario durante ${positiveDays} días\n` +
  `📊 EMA: ${emaStart.toFixed(2)} → ${emaCurrent.toFixed(2)}\n\n` +
  `💡 Inspección preventiva recomendada antes de anomalía crítica.`;

return [{ json: {
  action: 'preventive_maintenance',
  area,
  avg_daily_growth_pct: Math.round(avgGrowth * 100) / 100,
  positive_growth_days: positiveDays,
  total_days: dailyData.length,
  ema_start: emaStart,
  ema_current: emaCurrent,
  priority,
  message,
  save_order: true,
  recomendacion: `Incremento sostenido de ${avgGrowth.toFixed(1)}% diario durante ${positiveDays} días. Revisar instalación eléctrica de ${area}.`,
  timestamp: new Date().toISOString()
} }];
